@page "/notepad"
@rendermode InteractiveServer
@inject IJSRuntime JS
@implements IAsyncDisposable

<PageTitle>Notepad</PageTitle>

<h1>Notepad</h1>

<textarea class="form-control mb-3" rows="12" @bind="content" @bind:event="oninput" @bind:after="OnContentChanged"></textarea>

<div class="d-flex align-items-center gap-3 mb-3">
    <button class="btn btn-primary" @onclick="SaveNow" disabled="@(!hasUnsavedChanges)">Save now</button>
    <button class="btn btn-outline-danger" @onclick="Clear">Clear</button>
    @if (lastSavedAt is not null)
    {
        <span class="text-muted">Last saved at @lastSavedAt.Value.ToString("HH:mm:ss")</span>
    }
</div>

@code {
    private string content = string.Empty;
    private string lastSavedContent = string.Empty;
    private DateTime? lastSavedAt;
    private bool hasUnsavedChanges;
    private System.Timers.Timer? autoSaveTimer;
    private IJSObjectReference? jsModule;
    private DotNetObjectReference<Notepad>? dotNetRef;

    private const string StorageKeyContent = "notepad-content";
    private const string StorageKeyTimestamp = "notepad-timestamp";

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (!firstRender) return;

        jsModule = await JS.InvokeAsync<IJSObjectReference>("import", "./Components/Pages/Notepad.razor.js");
        dotNetRef = DotNetObjectReference.Create(this);

        var saved = await jsModule.InvokeAsync<string?>("loadContent", StorageKeyContent);
        var savedTimestamp = await jsModule.InvokeAsync<string?>("loadContent", StorageKeyTimestamp);

        if (!string.IsNullOrEmpty(saved))
        {
            content = saved;
            lastSavedContent = saved;
            if (DateTime.TryParse(savedTimestamp, out var ts))
            {
                lastSavedAt = ts;
            }
            StateHasChanged();
        }

        autoSaveTimer = new System.Timers.Timer(30_000);
        autoSaveTimer.Elapsed += async (_, _) => await InvokeAsync(AutoSave);
        autoSaveTimer.Start();
    }

    private async Task OnContentChanged()
    {
        hasUnsavedChanges = content != lastSavedContent;
        await UpdateBeforeUnload();
    }

    private async Task AutoSave()
    {
        if (hasUnsavedChanges)
        {
            await SaveContent();
            StateHasChanged();
        }
    }

    private async Task SaveNow()
    {
        await SaveContent();
    }

    private async Task SaveContent()
    {
        if (jsModule is null) return;

        lastSavedContent = content;
        lastSavedAt = DateTime.Now;
        hasUnsavedChanges = false;

        await jsModule.InvokeVoidAsync("saveContent", StorageKeyContent, content);
        await jsModule.InvokeVoidAsync("saveContent", StorageKeyTimestamp, lastSavedAt.Value.ToString("o"));
        await UpdateBeforeUnload();
    }

    private async Task Clear()
    {
        if (jsModule is null) return;

        content = string.Empty;
        lastSavedContent = string.Empty;
        lastSavedAt = null;
        hasUnsavedChanges = false;

        await jsModule.InvokeVoidAsync("removeContent", StorageKeyContent);
        await jsModule.InvokeVoidAsync("removeContent", StorageKeyTimestamp);
        await UpdateBeforeUnload();
    }

    private async Task UpdateBeforeUnload()
    {
        if (jsModule is not null)
        {
            await jsModule.InvokeVoidAsync("setBeforeUnload", hasUnsavedChanges);
        }
    }

    public async ValueTask DisposeAsync()
    {
        autoSaveTimer?.Stop();
        autoSaveTimer?.Dispose();

        if (jsModule is not null)
        {
            await jsModule.InvokeVoidAsync("setBeforeUnload", false);
            await jsModule.DisposeAsync();
        }

        dotNetRef?.Dispose();
    }
}

let beforeUnloadHandler = null;

export function saveContent(key, value) {
    localStorage.setItem(key, value);
}

export function loadContent(key) {
    return localStorage.getItem(key);
}

export function removeContent(key) {
    localStorage.removeItem(key);
}

export function setBeforeUnload(enable) {
    if (enable) {
        if (!beforeUnloadHandler) {
            beforeUnloadHandler = (e) => {
                e.preventDefault();
            };
            window.addEventListener("beforeunload", beforeUnloadHandler);
        }
    } else {
        if (beforeUnloadHandler) {
            window.removeEventListener("beforeunload", beforeUnloadHandler);
            beforeUnloadHandler = null;
        }
    }
}

